<?php
namespace App\Http\Controllers\Admin;
use App\Http\Controllers\Controller;use App\Models\Article;use Illuminate\Http\Request;use Illuminate\Support\Str;
class ArticleController extends Controller { public function index(){return view('admin.articles.index',['articles'=>Article::latest()->paginate(20)]);} public function store(Request $r){$d=$this->data($r);$d['user_id']=auth()->id();$d['slug']=Str::slug($d['title']).'-'.Str::lower(Str::random(5));$d['published_at']=$d['status']==='published'?now():null;Article::create($d);return back()->with('success','Artikel ditambahkan.');} public function update(Request $r,Article $article){$d=$this->data($r);$d['published_at']=$d['status']==='published'?($article->published_at?:now()):null;$article->update($d);return back()->with('success','Artikel diperbarui.');} public function destroy(Article $article){$article->delete();return back()->with('success','Artikel dihapus.');} private function data(Request $r){return $r->validate(['title'=>'required|max:200','excerpt'=>'nullable|max:500','content'=>'required','status'=>'required|in:draft,published']);} }
